import {IBaseAuction} from "src/interfaces/IBaseAuction.sol";
import {IFeeAggregator} from "src/interfaces/IFeeAggregator.sol";

import {Caller} from "src/Caller.sol";
import {PriceManager} from "src/PriceManager.sol";
